import React, { useEffect } from 'react';
import { Link } from 'react-router-dom';

function Downloads() {
  useEffect(() => {
    const observerOptions = {
      threshold: 0.1,
      rootMargin: '0px 0px -50px 0px'
    };

    const observer = new IntersectionObserver((entries) => {
      entries.forEach(entry => {
        if (entry.isIntersecting) {
          entry.target.classList.add('reveal');
          observer.unobserve(entry.target);
        }
      });
    }, observerOptions);

    const animatedElements = document.querySelectorAll('.animate-up');
    animatedElements.forEach(el => observer.observe(el));

    return () => {
      observer.disconnect();
    };
  }, []);

  const downloadOptions = [
    {
      id: 1,
      name: "windows 10 or 11 ",
      platform: "Windows",
      version: "v1.0.0",
      icon: "fab fa-windows",
      description: "النسخة الكاملة لإدارة المكتب من الكمبيوتر المكتبي.",
      size: "91.2 MB",
      link:"https://github.com/mostafaaamen/lawyermangement/releases/download/v1.0.0/Lawyer.Management.Setup.1.0.0.exe"
    },
  
  
  ];

  return (
    <div className="downloads-page">
      {/* Simple Navbar for Downloads Page */}
      <nav className="navbar glass">
        <Link to="/" className="logo">
          <i className="fas fa-arrow-right" style={{marginLeft: '15px'}}></i>
          العودة للرئيسية
        </Link>
        <div className="logo" style={{fontSize: '1.2rem'}}>صفحة التحميلات</div>
      </nav>

      <section className="section downloads animate-up">
        <h2 className="section-title">مركز التحميل</h2>
        <p className="section-subtitle">اختر النسخة المناسبة لجهازك وابدأ العمل بذكاء</p>
        <div className="downloads-content">
          <div className="downloads-grid">
            {downloadOptions.map((item, index) => (
              <div key={item.id} className={`download-card glass animate-up delay-${index + 1}`}>
                <span className="version-badge">{item.version}</span>
                <i className={`${item.icon} fa-4x`}></i>
                <div className="download-info">
                  <h3>{item.name}</h3>
                  <p>{item.description}</p>
                  <div style={{color: 'var(--accent)', marginBottom: '1.5rem', fontSize: '0.9rem'}}>
                    <i className="fas fa-file-zipper" style={{marginLeft: '5px'}}></i>
                    الحجم: {item.size}
                  </div>
                </div>
                <a href={item.link} target="_blank" rel="noopener noreferrer" className="btn-primary glow" style={{width: '100%', justifyContent: 'center'}}>
                  <i className="fas fa-cloud-arrow-down"></i>
                  تحميل الآن
                </a>
              </div>
            ))}
          </div>
          
          <div className="creative-image-container animate-up delay-3" style={{marginTop: '3rem', width: '100%', display: 'flex', justifyContent: 'center'}}>
             <img src="./images/503.png" alt="Downloads" className="hero-img-element floating" style={{maxWidth: '600px'}} />
          </div>
        </div>
      </section>

      {/* Footer */}
      <footer className="footer">
        <div className="footer-bottom">
          <p>© 2026 AZMOS MANAGEMENT LAWYER. جميع الحقوق محفوظة.</p>
        </div>
      </footer>
    </div>
  );
}

export default Downloads;
